package analytics

import (
	"context"
	"errors"

	marketmath "socialpredict/internal/domain/math/market"
	"socialpredict/setup"
)

// DebtStats represents aggregated debt metrics.
type DebtStats struct {
	UserCount         int64
	UnusedDebt        int64
	RealizedProfits   int64
	TotalDebtCapacity int64
}

// MarketVolumeStats represents market volume metrics.
type MarketVolumeStats struct {
	MarketCreationFees int64
	ActiveBetVolume    int64
}

// ComputeSystemMetrics aggregates system-wide monetary metrics.
func (s *Service) ComputeSystemMetrics(ctx context.Context) (*SystemMetrics, error) {
	if s.repo == nil {
		return nil, errors.New("repository not provided")
	}
	if s.econLoader == nil {
		return nil, errors.New("economic configuration loader not provided")
	}

	s.ensureStrategyDefaults()
	econ := s.econLoader()

	debtStats, err := s.debtCalculator.Calculate(ctx, s.repo, econ)
	if err != nil {
		return nil, err
	}

	volumeStats, err := s.volumeCalculator.Calculate(ctx, s.repo, econ)
	if err != nil {
		return nil, err
	}

	participationFees, err := s.feeCalculator.CalculateParticipationFees(ctx, s.repo, econ)
	if err != nil {
		return nil, err
	}

	return s.metricsAssembler.Assemble(econ, debtStats, volumeStats, participationFees), nil
}

// DefaultDebtCalculator implements the existing debt policy.
type DefaultDebtCalculator struct{}

func (c DefaultDebtCalculator) Calculate(ctx context.Context, repo DebtRepository, econ *setup.EconomicConfig) (*DebtStats, error) {
	users, err := repo.ListUsers(ctx)
	if err != nil {
		return nil, err
	}

	stats := &DebtStats{
		UserCount: int64(len(users)),
	}

	for _, user := range users {
		balance := user.AccountBalance
		if balance > 0 {
			stats.RealizedProfits += balance
		}
		usedDebt := int64(0)
		if balance < 0 {
			usedDebt = -balance
		}
		stats.UnusedDebt += econ.Economics.User.MaximumDebtAllowed - usedDebt
	}

	stats.TotalDebtCapacity = econ.Economics.User.MaximumDebtAllowed * stats.UserCount
	return stats, nil
}

// DefaultVolumeCalculator implements the existing volume policy.
type DefaultVolumeCalculator struct{}

func (c DefaultVolumeCalculator) Calculate(ctx context.Context, repo VolumeRepository, econ *setup.EconomicConfig) (*MarketVolumeStats, error) {
	markets, err := repo.ListMarkets(ctx)
	if err != nil {
		return nil, err
	}

	stats := &MarketVolumeStats{
		MarketCreationFees: int64(len(markets)) * econ.Economics.MarketIncentives.CreateMarketCost,
	}

	for _, market := range markets {
		if market.IsResolved {
			continue
		}

		bets, err := repo.ListBetsForMarket(ctx, market.ID)
		if err != nil {
			return nil, err
		}
		stats.ActiveBetVolume += marketmath.GetMarketVolume(bets)
	}

	return stats, nil
}

// DefaultFeeCalculator implements the existing participation fee policy.
type DefaultFeeCalculator struct{}

func (c DefaultFeeCalculator) CalculateParticipationFees(ctx context.Context, repo FeeRepository, econ *setup.EconomicConfig) (int64, error) {
	betsOrdered, err := repo.ListBetsOrdered(ctx)
	if err != nil {
		return 0, err
	}

	type userMarket struct {
		marketID uint
		username string
	}

	seen := make(map[userMarket]bool)
	var participationFees int64

	for _, b := range betsOrdered {
		if b.Amount <= 0 {
			continue
		}
		key := userMarket{marketID: b.MarketID, username: b.Username}
		if !seen[key] {
			participationFees += econ.Economics.Betting.BetFees.InitialBetFee
			seen[key] = true
		}
	}

	return participationFees, nil
}

// DefaultMetricsAssembler builds the SystemMetrics DTO from calculator outputs.
type DefaultMetricsAssembler struct{}

func (a DefaultMetricsAssembler) Assemble(econ *setup.EconomicConfig, debt *DebtStats, volume *MarketVolumeStats, participationFees int64) *SystemMetrics {
	bonusesPaid := debt.RealizedProfits
	totalUtilized := debt.UnusedDebt + volume.ActiveBetVolume + volume.MarketCreationFees + participationFees + bonusesPaid
	surplus := debt.TotalDebtCapacity - totalUtilized
	balanced := surplus == 0

	return &SystemMetrics{
		MoneyCreated: MoneyCreated{
			UserDebtCapacity: NewInt64Metric(debt.TotalDebtCapacity, "numUsers × maxDebtPerUser", "Total credit capacity made available to all users"),
			NumUsers:         NewInt64Metric(debt.UserCount, "", "Total number of registered users"),
		},
		MoneyUtilized: MoneyUtilized{
			UnusedDebt:         NewInt64Metric(debt.UnusedDebt, "Σ(maxDebtPerUser - max(0, -balance))", "Remaining borrowing capacity available to users"),
			ActiveBetVolume:    NewInt64Metric(volume.ActiveBetVolume, "Σ(unresolved_market_volumes)", "Total value of bets currently active in unresolved markets (excludes fees and subsidies)"),
			MarketCreationFees: NewInt64Metric(volume.MarketCreationFees, "number_of_markets × creation_fee_per_market", "Fees collected from users creating new markets"),
			ParticipationFees:  NewInt64Metric(participationFees, "Σ(first_bet_per_user_per_market × participation_fee)", "Fees collected from first-time participation in each market"),
			BonusesPaid:        NewInt64Metric(bonusesPaid, "", "System bonuses paid to users and realized profits currently held in user balances"),
			TotalUtilized:      NewInt64Metric(totalUtilized, "unusedDebt + activeBetVolume + marketCreationFees + participationFees + bonusesPaid", "Total debt capacity that has been utilized across all categories"),
		},
		Verification: Verification{
			Balanced: NewBoolMetric(balanced, "Whether total created equals total utilized (perfect accounting balance)"),
			Surplus:  NewInt64Metric(surplus, "userDebtCapacity - totalUtilized", "Positive = unused capacity, Negative = over-utilization (indicates accounting error)"),
		},
	}
}

package bets

import (
	"context"
	"strings"
	"time"

	"socialpredict/internal/domain/boundary"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
	"socialpredict/setup"
)

func normalizeOutcome(outcome string) string {
	switch strings.ToUpper(strings.TrimSpace(outcome)) {
	case "YES":
		return "YES"
	case "NO":
		return "NO"
	default:
		return ""
	}
}

func validatePlaceRequest(req PlaceRequest) (string, error) {
	outcome := normalizeOutcome(req.Outcome)
	if outcome == "" {
		return "", ErrInvalidOutcome
	}
	if req.Amount <= 0 {
		return "", ErrInvalidAmount
	}
	return outcome, nil
}

func validateSellRequest(req SellRequest) (string, error) {
	outcome := normalizeOutcome(req.Outcome)
	if outcome == "" {
		return "", ErrInvalidOutcome
	}
	if req.Amount <= 0 {
		return "", ErrInvalidAmount
	}
	return outcome, nil
}

type defaultPlaceValidator struct{}

func (defaultPlaceValidator) Validate(ctx context.Context, req PlaceRequest) (string, error) {
	return validatePlaceRequest(req)
}

type defaultSellValidator struct{}

func (defaultSellValidator) Validate(ctx context.Context, req SellRequest) (string, error) {
	return validateSellRequest(req)
}

// marketGate ensures markets are open before interacting with them.
type marketGate struct {
	markets MarketReader
	clock   Clock
}

func (g marketGate) Open(ctx context.Context, marketID int64) (*dmarkets.Market, error) {
	market, err := g.markets.GetMarket(ctx, marketID)
	if err != nil {
		return nil, err
	}
	if market == nil {
		return nil, dmarkets.ErrMarketNotFound
	}
	if err := ensureMarketOpen(market, g.clock.Now()); err != nil {
		return nil, err
	}
	return market, nil
}

func ensureMarketOpen(market *dmarkets.Market, now time.Time) error {
	if market.Status == "resolved" || now.After(market.ResolutionDateTime) {
		return ErrMarketClosed
	}
	return nil
}

type feeCalculator struct {
	econ *setup.EconomicConfig
}

func (f feeCalculator) Calculate(hasBet bool, amount int64) betFees {
	fees := betFees{
		initialFee:     0,
		transactionFee: int64(f.econ.Economics.Betting.BetFees.BuySharesFee),
	}
	if !hasBet {
		fees.initialFee = int64(f.econ.Economics.Betting.BetFees.InitialBetFee)
	}
	fees.totalCost = amount + fees.initialFee + fees.transactionFee
	return fees
}

type balanceGuard struct {
	maxDebtAllowed int64
}

func (g balanceGuard) EnsureSufficient(balance, totalCost int64) error {
	if balance-totalCost < -g.maxDebtAllowed {
		return ErrInsufficientBalance
	}
	return nil
}

type betLedger struct {
	repo  BetWriter
	users TransactionRecorder
}

func (l betLedger) ChargeAndRecord(ctx context.Context, bet *boundary.Bet, totalCost int64) error {
	if err := l.users.ApplyTransaction(ctx, bet.Username, totalCost, dusers.TransactionBuy); err != nil {
		return err
	}

	if err := l.repo.Create(ctx, bet); err != nil {
		_ = l.users.ApplyTransaction(ctx, bet.Username, totalCost, dusers.TransactionRefund)
		return err
	}
	return nil
}

func (l betLedger) CreditSale(ctx context.Context, bet *boundary.Bet, saleValue int64) error {
	if err := l.users.ApplyTransaction(ctx, bet.Username, saleValue, dusers.TransactionSale); err != nil {
		return err
	}
	if err := l.repo.Create(ctx, bet); err != nil {
		_ = l.users.ApplyTransaction(ctx, bet.Username, saleValue, dusers.TransactionBuy)
		return err
	}
	return nil
}

}

// WithFeeCalculator overrides the fee calculator.
func WithFeeCalculator(c FeeCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.fees = feeCalculatorOrDefault(c, s.econ)
		}
	}
}

// WithBalanceGuard overrides the balance guard.
func WithBalanceGuard(g BalanceGuard) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.balances = balanceGuardOrDefault(g, s.econ)
		}
	}
}

// WithBetLedger overrides the bet ledger.
func WithBetLedger(l BetLedger) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.ledger = betLedgerOrDefault(l, s.repo, s.users)
		}
	}
}

// WithSaleCalculator overrides the sale calculator.
func WithSaleCalculator(c SaleCalculator) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.saleCalculator = saleCalculatorOrDefault(c, s.econ)
		}
	}
}

// WithClock overrides the service clock.
func WithClock(clock Clock) ServiceOption {
	return func(s *Service) {
		if s != nil {
			s.clock = clockOrDefault(clock)
		}
	}
}

// NewService constructs a bets service.
func NewService(repo Repository, markets MarketService, users UserService, econ *setup.EconomicConfig, clock Clock, opts ...ServiceOption) *Service {
	s := &Service{
		repo:    repo,
		markets: markets,
		users:   users,
		econ:    econOrDefault(econ),
		clock:   clockOrDefault(clock),
	}

	for _, opt := range opts {
		opt(s)
	}

	s.ensureDefaults()
	return s
}

func (s *Service) ensureDefaults() {
	if s == nil {
		return
	}

	s.clock = clockOrDefault(s.clock)
	s.placeValidator = placeValidatorOrDefault(s.placeValidator)
	s.sellValidator = sellValidatorOrDefault(s.sellValidator)
	s.marketGate = marketGateOrDefault(s.marketGate, s.markets, s.clock)
	s.fees = feeCalculatorOrDefault(s.fees, s.econ)
	s.balances = balanceGuardOrDefault(s.balances, s.econ)
	s.ledger = betLedgerOrDefault(s.ledger, s.repo, s.users)
	s.saleCalculator = saleCalculatorOrDefault(s.saleCalculator, s.econ)
}

package config

import (
	"bytes"
	"errors"

	"gopkg.in/yaml.v3"
)

var (
	ErrNilSource  = errors.New("config source is nil")
	ErrNilDecoder = errors.New("config decoder is nil")
)

// Source returns raw configuration bytes from the current source asset.
type Source interface {
	Bytes() ([]byte, error)
}

type SourceFunc func() ([]byte, error)

func (f SourceFunc) Bytes() ([]byte, error) {
	return f()
}

// StaticSource wraps immutable source bytes for loader construction.
type StaticSource []byte

func (s StaticSource) Bytes() ([]byte, error) {
	return bytes.Clone(s), nil
}

// Decoder transforms source bytes into the owned application-policy snapshot.
type Decoder interface {
	Decode(data []byte) (*AppConfig, error)
}

type DecoderFunc func(data []byte) (*AppConfig, error)

func (f DecoderFunc) Decode(data []byte) (*AppConfig, error) {
	return f(data)
}

// AssetLoader composes a source asset and decoder into the runtime loader seam.
type AssetLoader struct {
	source  Source
	decoder Decoder
}

// NewAssetLoader creates an explicit loader from a source asset and decoder.
func NewAssetLoader(source Source, decoder Decoder) Loader {
	return AssetLoader{
		source:  source,
		decoder: decoder,
	}
}

// NewYAMLLoader loads the owned application-policy config from YAML source bytes.
func NewYAMLLoader(source Source) Loader {
	return NewAssetLoader(source, DecoderFunc(decodeYAML))
}

func (l AssetLoader) Load() (*AppConfig, error) {
	if l.source == nil {
		return nil, ErrNilSource
	}
	if l.decoder == nil {
		return nil, ErrNilDecoder
	}

	data, err := l.source.Bytes()
	if err != nil {
		return nil, err
	}

	return l.decoder.Decode(data)
}

func decodeYAML(data []byte) (*AppConfig, error) {
	cfg := &AppConfig{}
	if len(data) == 0 {
		return cfg, nil
	}
	if err := yaml.Unmarshal(data, cfg); err != nil {
		return nil, err
	}
	return cfg, nil
}

package config

import "socialpredict/setup"

// Service exposes typed access to application configuration slices.
type Service interface {
	Current() *AppConfig
	Economics() Economics
	Frontend() Frontend
	ChartSigFigs() int
}

// Loader loads configuration from its source of truth.
type Loader interface {
	Load() (*AppConfig, error)
}

type LoaderFunc func() (*AppConfig, error)

func (f LoaderFunc) Load() (*AppConfig, error) {
	return f()
}

type RuntimeService struct {
	current *AppConfig
}

func NewService(loader Loader) (*RuntimeService, error) {
	if loader == nil {
		return NewStaticService((*AppConfig)(nil)), nil
	}

	cfg, err := loader.Load()
	if err != nil {
		return nil, err
	}

	return NewStaticService(cfg), nil
}

// NewStaticService preserves a static config snapshot, including legacy setup snapshots.
func NewStaticService(cfg any) *RuntimeService {
	return &RuntimeService{current: normalizeConfig(cfg)}
}

func (s *RuntimeService) Current() *AppConfig {
	if s == nil || s.current == nil {
		return &AppConfig{}
	}
	return s.current
}

func (s *RuntimeService) Economics() Economics {
	return s.Current().Economics
}

func (s *RuntimeService) Frontend() Frontend {
	return s.Current().Frontend
}

func (s *RuntimeService) ChartSigFigs() int {
	return ClampChartSigFigs(s.Frontend())
}

func normalizeConfig(cfg any) *AppConfig {
	switch typed := cfg.(type) {
	case nil:
		return &AppConfig{}
	case *AppConfig:
		if typed == nil {
			return &AppConfig{}
		}
		return typed
	case AppConfig:
		cfgCopy := typed
		return &cfgCopy
	case *setup.EconomicConfig:
		return FromSetup(typed)
	case setup.EconomicConfig:
		return FromSetup(&typed)
	default:
		return &AppConfig{}
	}
}

